class BloodCompartment{constructor(t){this._model=t,this.pres=0,this.pres_recoil=0,this.pres_ext=0,this.pres_cont=0,this.el=0,this.el_max_fac=1,this.el_min_fac=1,this.vol_u_fac=1,this.el_k1_fac=1,this.el_act=0,this.compound_names=[],this._no_compounds=0,this.fvatp=0,this.initialized=!1}calcElastance(){let t=this.el_min*this.el_min_fac,s=this.el_k1*this.el_k1_fac*Math.pow(this.vol-this.vol_u,2),i=this.el_max*this.el_max_fac*this.el_act;return t+s+i}calcPressure(){return this.el=this.calcElastance(),this.pres_recoil=(this.vol-this.vol_u*this.vol_u_fac)*this.el,this.pres_recoil+this.pres_ext+this.pres_cont}volIn(t,s){this.vol+=t,this.vol<0&&(this.vol=0),this.calcCompoundsConcentrations(t,s)}volOut(t){this.vol-=t,this.vol<0&&(this.vol=0)}calcCompoundsConcentrations(t,s){for(let i=0;i<this.no_compounds;i++){const o=this.compound_names[i];let e=this[o];const l=s[o],h=(l-e)*t;e=(e*this.vol+h)/this.vol,e<0&&(e=0),this[o]=e}}modelStep(){this.is_enabled&&(this.initialized||this._model.components.Blood.initializeBloodCompartment(this),this.pres=this.calcPressure())}}